/** Independent threat/security root with explainable whole-city infiltration decisions. */
public final class ThreatSavedData extends SavedData implements PatrolRouteRepository, PatrolAssignmentRepository {
    public static final int SCHEMA_VERSION=9;
    private static final Logger LOGGER=LogUtils.getLogger();
    public enum Phase{CALM,OMEN,WARNING,WAVE,COOLDOWN}
    public record EdgeKey(UUID cityId,long chunk,TerritoryTopology.Direction direction){}
    public record CellKey(UUID cityId,long chunk)implements Comparable<CellKey>{public int compareTo(CellKey other){int city=cityId.compareTo(other.cityId);return city!=0?city:Long.compare(chunk,other.chunk);}}
    public record EdgePage(List<Map.Entry<EdgeKey,State>> entries,boolean truncated,int examined){}
    public record EdgeBatch(List<Map.Entry<EdgeKey,State>>entries,EdgeKey nextCursor,boolean wrapped,int examined){public EdgeBatch{entries=List.copyOf(entries);}}
    public record SecurityCellPage(List<SecurityCell> cells,boolean truncated,int examined){}
    public record PatrolCoverage(long lastPatrolledAt,long lastVisibleGuardAt,UUID assignmentId){public PatrolCoverage{if(lastPatrolledAt<0||lastVisibleGuardAt<0||assignmentId==null)throw new IllegalArgumentException("invalid patrol coverage");}}
    public record CoverageEvidence(double patrol,double visibleGuard,boolean patrolLinked,boolean guardLinked){}
    public record PatrolAssignmentBatch(List<PatrolAssignment>assignments,UUID nextCursor,boolean wrapped,int examined){public PatrolAssignmentBatch{assignments=List.copyOf(assignments);}}
    public record InvasionCommitmentBatch(List<InvasionCommitment>commitments,UUID nextCursor,boolean wrapped,int examined){public InvasionCommitmentBatch{commitments=List.copyOf(commitments);}}
    public enum MobAdmission{INACTIVE,LEGACY_ACTIVE,SURVIVOR,DEFEATED}
    public record State(double pressure,Phase phase,long phaseStartedAt,long cooldownUntil,int wave,UUID invasionId,int remainingMobs,int failedDefenses,long lastUpdatedAt){public State{if(phase==null||remainingMobs<0||phase==Phase.WAVE&&(invasionId==null||wave<1)||phase!=Phase.WAVE&&remainingMobs!=0)throw new IllegalArgumentException("invalid invasion wave state");}public State(double pressure,Phase phase,long phaseStartedAt,long cooldownUntil,int wave,UUID invasionId,int failedDefenses,long lastUpdatedAt){this(pressure,phase,phaseStartedAt,cooldownUntil,wave,invasionId,0,failedDefenses,lastUpdatedAt);}public static State calm(long now){return new State(0,Phase.CALM,now,0,0,null,0,0,now);}public State withRemainingMobs(int value,long now){return new State(pressure,phase,phaseStartedAt,cooldownUntil,wave,invasionId,Math.max(0,value),failedDefenses,now);}}
    private static final Codec<ThreatSavedData>CODEC=CompoundTag.CODEC.xmap(ThreatSavedData::load,ThreatSavedData::saveTag);
    private static final SavedDataType<ThreatSavedData>TYPE=new SavedDataType<>(Identifier.fromNamespaceAndPath("civitas","threat_events"),ThreatSavedData::new,CODEC);
    private static final Comparator<EdgeKey>EDGE_ORDER=Comparator.comparing(EdgeKey::cityId).thenComparingLong(EdgeKey::chunk).thenComparingInt(key->key.direction().ordinal());
    private final NavigableMap<EdgeKey,State>states=new TreeMap<>(EDGE_ORDER);
    private final NavigableMap<CellKey,SecurityCell>securityCells=new TreeMap<>();
    private final Map<CellKey,PatrolCoverage>patrolCoverage=new HashMap<>();
    private final Map<EdgeKey,InfiltrationPlan>infiltrationPlans=new HashMap<>();
    private final NavigableMap<UUID,InvasionCommitment>invasionCommitments=new TreeMap<>();
    private final NavigableMap<UUID,PatrolRoute>patrolRoutes=new TreeMap<>();
    private final NavigableMap<UUID,PatrolAssignment>patrolAssignments=new TreeMap<>();
    private final Map<UUID,LinkedHashSet<EdgeKey>>edgeCityIndex=new HashMap<>();
    private final Map<UUID,EdgeKey>invasionEdgeIndex=new HashMap<>();
    private final Map<CellKey,LinkedHashSet<EdgeKey>>edgeChunkIndex=new HashMap<>();
    private final Map<UUID,LinkedHashSet<CellKey>>cellCityIndex=new HashMap<>();
    private final Map<UUID,LinkedHashSet<UUID>>patrolCityIndex=new HashMap<>();
    private final Map<UUID,LinkedHashSet<UUID>>patrolPostIndex=new HashMap<>();
    private final Map<UUID,LinkedHashSet<UUID>>assignmentCityIndex=new HashMap<>();
    private final Map<UUID,UUID>assignmentCitizenIndex=new HashMap<>();
    private final Map<RouteShiftKey,UUID>assignmentRouteShiftIndex=new HashMap<>();
    private final Map<UUID,LinkedHashSet<UUID>>assignmentRouteIndex=new HashMap<>();
    private boolean readOnly;private CompoundTag protectedRoot;private int quarantinedEdges,quarantinedSecurityCells,quarantinedPatrolRoutes,quarantinedPatrolAssignments,quarantinedPatrolCoverage,quarantinedInfiltrationPlans,quarantinedInvasionCommitments;private String migrationResult="created_v9";
    private record RouteShiftKey(UUID routeId,GuardShift shift){}

    public static ThreatSavedData get(MinecraftServer server){return server.overworld().getDataStorage().computeIfAbsent(TYPE);}
    public State get(EdgeKey key,long now){return states.getOrDefault(key,State.calm(now));}
    public void put(EdgeKey key,State state){if(!readOnly){EdgeKey conflict=state.invasionId()==null?null:invasionEdgeIndex.get(state.invasionId());if(conflict!=null&&!conflict.equals(key))throw new IllegalArgumentException("invasion id already belongs to another edge");State previous=states.put(key,state);if(previous==null)indexEdge(key);else if(previous.invasionId()!=null)invasionEdgeIndex.remove(previous.invasionId(),key);if(state.invasionId()!=null)invasionEdgeIndex.put(state.invasionId(),key);if(state.phase()!=Phase.WARNING&&state.phase()!=Phase.WAVE)infiltrationPlans.remove(key);if(previous!=null&&previous.invasionId()!=null&&(state.phase()!=Phase.WAVE||!previous.invasionId().equals(state.invasionId())))invasionCommitments.remove(previous.invasionId());setDirty();}}
    public void remove(EdgeKey key){if(!readOnly){State removed=states.get(key);if(removed!=null){unindexEdge(key);states.remove(key);infiltrationPlans.remove(key);if(removed.invasionId()!=null)invasionCommitments.remove(removed.invasionId());setDirty();}}}
    public Map<EdgeKey,State>states(){return Map.copyOf(states);}
    public boolean activeInvasion(UUID invasionId){EdgeKey key=invasionId==null?null:invasionEdgeIndex.get(invasionId);State state=key==null?null:states.get(key);return state!=null&&state.phase()==Phase.WAVE&&invasionId.equals(state.invasionId());}
    public boolean recordInvasionMobDeath(UUID invasionId,long now){return recordInvasionMobDeath(invasionId,null,now);}
    public boolean recordInvasionMobDeath(UUID invasionId,UUID enemyId,long now){if(readOnly||invasionId==null)return false;EdgeKey key=invasionEdgeIndex.get(invasionId);State state=key==null?null:states.get(key);if(state==null||state.phase()!=Phase.WAVE||state.remainingMobs()<=0)return false;InvasionCommitment commitment=invasionCommitments.get(invasionId);if(commitment!=null){UUID target=enemyId==null?(commitment.survivingEnemyIds().isEmpty()?null:commitment.survivingEnemyIds().getFirst()):enemyId;if(target==null||!commitment.survivingEnemy(target))return false;invasionCommitments.put(invasionId,commitment.enemyDied(target,now));}states.put(key,state.withRemainingMobs(state.remainingMobs()-1,now));setDirty();return true;}
    public MobAdmission mobAdmission(UUID invasionId,UUID enemyId){if(!activeInvasion(invasionId))return MobAdmission.INACTIVE;InvasionCommitment commitment=invasionCommitments.get(invasionId);EdgeKey key=invasionEdgeIndex.get(invasionId);State state=key==null?null:states.get(key);if(commitment==null||state==null||commitment.wave()!=state.wave())return MobAdmission.LEGACY_ACTIVE;return commitment.survivingEnemy(enemyId)?MobAdmission.SURVIVOR:MobAdmission.DEFEATED;}
    public EdgePage edgePage(UUID cityId,int limit){ArrayList<Map.Entry<EdgeKey,State>>out=new ArrayList<>();int cap=Math.max(0,limit),examined=0;for(EdgeKey key:edgeCityIndex.getOrDefault(cityId,new LinkedHashSet<>())){examined++;if(out.size()>=cap)return new EdgePage(List.copyOf(out),true,examined);State state=states.get(key);if(state!=null)out.add(Map.entry(key,state));}return new EdgePage(List.copyOf(out),false,examined);}
    public EdgeBatch edgeBatch(EdgeKey after,int limit){int cap=Math.max(0,limit);if(cap==0||states.isEmpty())return new EdgeBatch(List.of(),after,false,0);ArrayList<Map.Entry<EdgeKey,State>>out=new ArrayList<>(Math.min(cap,states.size()));EdgeKey key=after==null?states.firstKey():states.higherKey(after);boolean wrapped=false;if(key==null){key=states.firstKey();wrapped=true;}int examined=0,maximum=Math.min(cap,states.size());while(out.size()<maximum){State state=states.get(key);if(state!=null)out.add(Map.entry(key,state));examined++;EdgeKey next=states.higherKey(key);if(next==null){wrapped=true;if(out.size()<maximum)next=states.firstKey();}key=next;}return new EdgeBatch(out,out.getLast().getKey(),wrapped,examined);}
    public List<Map.Entry<EdgeKey,State>>edgesAt(UUID cityId,long chunk){ArrayList<Map.Entry<EdgeKey,State>>out=new ArrayList<>(4);for(EdgeKey key:edgeChunkIndex.getOrDefault(new CellKey(cityId,chunk),new LinkedHashSet<>())){State state=states.get(key);if(state!=null)out.add(Map.entry(key,state));}return List.copyOf(out);}
    public Optional<SecurityCell>securityCell(UUID cityId,long chunk){return Optional.ofNullable(securityCells.get(new CellKey(cityId,chunk)));}
    public Collection<SecurityCell>securityCells(UUID cityId){return securityCellPage(cityId,Integer.MAX_VALUE).cells();}
    public List<SecurityCell>securityCells(UUID cityId,int limit){return securityCellPage(cityId,limit).cells();}
    public SecurityCellPage securityCellPage(UUID cityId,int limit){ArrayList<SecurityCell>out=new ArrayList<>();int cap=Math.max(0,limit),examined=0;for(CellKey key:cellCityIndex.getOrDefault(cityId,new LinkedHashSet<>())){examined++;if(out.size()>=cap)return new SecurityCellPage(List.copyOf(out),true,examined);SecurityCell cell=securityCells.get(key);if(cell!=null)out.add(cell);}return new SecurityCellPage(List.copyOf(out),false,examined);}
    public Collection<SecurityCell>securityCells(){return List.copyOf(securityCells.values());}
    public SecurityCellMaintenanceBatch securityCellMaintenanceBatch(CellKey after,int limit){int cap=Math.max(0,limit);ArrayList<Map.Entry<CellKey,SecurityCell>>out=new ArrayList<>(Math.min(cap,securityCells.size()));if(cap>0)for(var entry:(after==null?securityCells:securityCells.tailMap(after,false)).entrySet()){out.add(Map.entry(entry.getKey(),entry.getValue()));if(out.size()>=cap)break;}CellKey next=out.isEmpty()?after:out.getLast().getKey();return new SecurityCellMaintenanceBatch(out,next,next==null||securityCells.higherKey(next)==null,out.size());}
    public record SecurityCellMaintenanceBatch(List<Map.Entry<CellKey,SecurityCell>>entries,CellKey nextCursor,boolean exhausted,int examined){public SecurityCellMaintenanceBatch{entries=List.copyOf(entries);}}
    public boolean removeSecurityCell(CellKey key){if(readOnly)return false;SecurityCell removed=securityCells.remove(key);if(removed==null)return false;unindexCell(key);setDirty();return true;}
    public void putSecurityCell(SecurityCell cell){if(!readOnly){CellKey key=new CellKey(cell.cityId(),cell.chunk());if(securityCells.put(key,cell)==null)indexCell(key);setDirty();}}
    public void retainSecurityCells(Set<CellKey>valid){if(readOnly)return;boolean changed=false;for(Iterator<CellKey>it=securityCells.keySet().iterator();it.hasNext();){CellKey key=it.next();if(!valid.contains(key)){it.remove();unindexCell(key);changed=true;}}if(changed)setDirty();}
    @Override public Optional<PatrolRoute>patrolRoute(UUID id){return Optional.ofNullable(patrolRoutes.get(id));}
    public List<PatrolRoute>patrolRoutes(UUID cityId,int limit){ArrayList<PatrolRoute>out=new ArrayList<>();int cap=Math.max(0,limit);for(UUID id:patrolCityIndex.getOrDefault(cityId,new LinkedHashSet<>())){if(out.size()>=cap)break;PatrolRoute route=patrolRoutes.get(id);if(route!=null)out.add(route);}return List.copyOf(out);}
    @Override public boolean createPatrolRoute(PatrolRoute route,int cityCap){if(readOnly||route==null||patrolRoutes.containsKey(route.id())||patrolCityIndex.getOrDefault(route.cityId(),new LinkedHashSet<>()).size()>=Math.max(0,cityCap))return false;patrolRoutes.put(route.id(),route);indexPatrol(route);setDirty();return true;}
    public int markPatrolRoutesForPostStale(UUID postId,String reason){if(readOnly||postId==null)return 0;int changed=0;for(UUID id:List.copyOf(patrolPostIndex.getOrDefault(postId,new LinkedHashSet<>()))){PatrolRoute route=patrolRoutes.get(id);if(route!=null&&route.status()==PatrolRoute.Status.VALID){patrolRoutes.put(id,route.stale(reason));markAssignmentsForRouteStale(id,reason);changed++;}}if(changed>0)setDirty();return changed;}
    public boolean markPatrolRouteStale(UUID routeId,String reason){if(readOnly)return false;PatrolRoute route=patrolRoutes.get(routeId);if(route==null||route.status()!=PatrolRoute.Status.VALID)return false;patrolRoutes.put(routeId,route.stale(reason));markAssignmentsForRouteStale(routeId,reason);setDirty();return true;}
    public int markPatrolRoutesOutsideTerritoryStale(UUID cityId,Set<Long>territoryChunks){if(readOnly||cityId==null)return 0;int changed=0;for(UUID id:List.copyOf(patrolCityIndex.getOrDefault(cityId,new LinkedHashSet<>()))){PatrolRoute route=patrolRoutes.get(id);if(route==null||route.status()!=PatrolRoute.Status.VALID)continue;boolean outside=route.nodes().stream().anyMatch(packed->!territoryChunks.contains(net.minecraft.world.level.ChunkPos.pack(net.minecraft.core.BlockPos.getX(packed)>>4,net.minecraft.core.BlockPos.getZ(packed)>>4)));if(outside){patrolRoutes.put(id,route.stale("territory_retracted"));markAssignmentsForRouteStale(id,"territory_retracted");changed++;}}if(changed>0)setDirty();return changed;}
    @Override public Optional<PatrolAssignment>patrolAssignment(UUID id){return Optional.ofNullable(patrolAssignments.get(id));}
    @Override public Optional<PatrolAssignment>patrolAssignmentForCitizen(UUID citizenId){UUID id=assignmentCitizenIndex.get(citizenId);return Optional.ofNullable(id==null?null:patrolAssignments.get(id));}
    public List<PatrolAssignment>patrolAssignments(UUID cityId,int limit){ArrayList<PatrolAssignment>out=new ArrayList<>();int cap=Math.max(0,limit);for(UUID id:assignmentCityIndex.getOrDefault(cityId,new LinkedHashSet<>())){if(out.size()>=cap)break;PatrolAssignment assignment=patrolAssignments.get(id);if(assignment!=null)out.add(assignment);}return List.copyOf(out);}
    public PatrolAssignmentBatch patrolAssignmentBatch(UUID after,int limit){int cap=Math.max(0,limit);if(cap==0||patrolAssignments.isEmpty())return new PatrolAssignmentBatch(List.of(),after,false,0);ArrayList<PatrolAssignment>out=new ArrayList<>(Math.min(cap,patrolAssignments.size()));UUID key=after==null?patrolAssignments.firstKey():patrolAssignments.higherKey(after);boolean wrapped=false;if(key==null){key=patrolAssignments.firstKey();wrapped=true;}int maximum=Math.min(cap,patrolAssignments.size()),examined=0;while(out.size()<maximum){PatrolAssignment value=patrolAssignments.get(key);if(value!=null)out.add(value);examined++;UUID next=patrolAssignments.higherKey(key);if(next==null){wrapped=true;if(out.size()<maximum)next=patrolAssignments.firstKey();}key=next;}return new PatrolAssignmentBatch(out,out.getLast().id(),wrapped,examined);}
    @Override public boolean createPatrolAssignment(PatrolAssignment assignment,int cityCap){if(readOnly||assignment==null||patrolAssignments.containsKey(assignment.id())||assignmentCitizenIndex.containsKey(assignment.citizenId())||assignmentRouteShiftIndex.containsKey(new RouteShiftKey(assignment.routeId(),assignment.shift()))||assignmentCityIndex.getOrDefault(assignment.cityId(),new LinkedHashSet<>()).size()>=Math.max(0,cityCap))return false;patrolAssignments.put(assignment.id(),assignment);indexAssignment(assignment);setDirty();return true;}
    @Override public boolean replacePatrolAssignment(PatrolAssignment assignment,long expectedRevision){if(readOnly||assignment==null)return false;PatrolAssignment current=patrolAssignments.get(assignment.id());if(current==null||current.revision()!=expectedRevision||!sameIdentity(current,assignment))return false;patrolAssignments.put(assignment.id(),assignment);setDirty();return true;}
    public void recordPatrolCoverage(UUID cityId,long chunk,UUID assignmentId,long now,boolean visibleGuard){if(readOnly||cityId==null||assignmentId==null||now<0)return;CellKey key=new CellKey(cityId,chunk);PatrolCoverage old=patrolCoverage.get(key);long visible=visibleGuard?now:old==null?0:old.lastVisibleGuardAt();patrolCoverage.put(key,new PatrolCoverage(now,visible,assignmentId));setDirty();}
    public CoverageEvidence coverageEvidence(UUID cityId,long chunk,long now,long memoryTicks){PatrolCoverage coverage=patrolCoverage.get(new CellKey(cityId,chunk));if(coverage==null)return new CoverageEvidence(0,0,false,false);double patrol=decay(now-coverage.lastPatrolledAt(),memoryTicks),guard=coverage.lastVisibleGuardAt()==0?0:decay(now-coverage.lastVisibleGuardAt(),memoryTicks);return new CoverageEvidence(patrol,guard,true,coverage.lastVisibleGuardAt()>0);}
    public Optional<InfiltrationPlan>infiltrationPlan(EdgeKey key){return Optional.ofNullable(infiltrationPlans.get(key));}
    public boolean putInfiltrationPlan(EdgeKey key,InfiltrationPlan plan){if(readOnly||key==null||plan==null||!key.cityId().equals(plan.cityId()))return false;State state=states.get(key);if(state==null||state.phase()!=Phase.WARNING&&state.phase()!=Phase.WAVE)return false;infiltrationPlans.put(key,plan);setDirty();return true;}
    public void clearInfiltrationPlan(EdgeKey key){if(!readOnly&&infiltrationPlans.remove(key)!=null)setDirty();}
    public Optional<InvasionCommitment>invasionCommitment(UUID invasionId){return Optional.ofNullable(invasionCommitments.get(invasionId));}
    public boolean createInvasionCommitment(InvasionCommitment commitment){if(readOnly||commitment==null||invasionCommitments.containsKey(commitment.invasionId()))return false;EdgeKey key=invasionEdgeIndex.get(commitment.invasionId());State state=key==null?null:states.get(key);if(state==null||state.phase()!=Phase.WAVE||!key.cityId().equals(commitment.cityId())||state.wave()!=commitment.wave()||state.remainingMobs()!=commitment.survivingEnemyIds().size())return false;invasionCommitments.put(commitment.invasionId(),commitment);setDirty();return true;}
    public boolean replaceInvasionCommitment(InvasionCommitment commitment,long expectedRevision){if(readOnly||commitment==null)return false;InvasionCommitment current=invasionCommitments.get(commitment.invasionId());if(current==null||current.revision()!=expectedRevision||!current.cityId().equals(commitment.cityId())||current.committedAt()!=commitment.committedAt())return false;invasionCommitments.put(commitment.invasionId(),commitment);setDirty();return true;}
    public boolean applyBackgroundRound(UUID invasionId,long expectedCommitmentRevision,int enemiesDefeated,long now){if(readOnly||enemiesDefeated<0)return false;InvasionCommitment current=invasionCommitments.get(invasionId);EdgeKey key=invasionEdgeIndex.get(invasionId);State state=key==null?null:states.get(key);if(current==null||current.revision()!=expectedCommitmentRevision||state==null||state.phase()!=Phase.WAVE||state.remainingMobs()!=current.survivingEnemyIds().size())return false;int defeated=Math.min(enemiesDefeated,state.remainingMobs());InvasionCommitment next=current.nextRound(defeated,now);invasionCommitments.put(invasionId,next);states.put(key,state.withRemainingMobs(state.remainingMobs()-defeated,now));setDirty();return true;}
    public boolean beginCommitmentWave(UUID invasionId,long expectedRevision,int wave,List<UUID>enemyIds,long now){if(readOnly)return false;InvasionCommitment current=invasionCommitments.get(invasionId);EdgeKey key=invasionEdgeIndex.get(invasionId);State state=key==null?null:states.get(key);if(current==null||current.revision()!=expectedRevision||state==null||state.phase()!=Phase.WAVE||state.wave()!=wave||state.remainingMobs()!=enemyIds.size())return false;invasionCommitments.put(invasionId,current.nextWave(wave,enemyIds,now));setDirty();return true;}
    public InvasionCommitmentBatch invasionCommitmentBatch(UUID after,int limit){int cap=Math.max(0,limit);if(cap==0||invasionCommitments.isEmpty())return new InvasionCommitmentBatch(List.of(),after,false,0);ArrayList<InvasionCommitment>out=new ArrayList<>();UUID key=after==null?invasionCommitments.firstKey():invasionCommitments.higherKey(after);boolean wrapped=false;if(key==null){key=invasionCommitments.firstKey();wrapped=true;}int maximum=Math.min(cap,invasionCommitments.size()),examined=0;while(out.size()<maximum){InvasionCommitment value=invasionCommitments.get(key);if(value!=null)out.add(value);examined++;UUID next=invasionCommitments.higherKey(key);if(next==null){wrapped=true;if(out.size()<maximum)next=invasionCommitments.firstKey();}key=next;}return new InvasionCommitmentBatch(out,out.getLast().invasionId(),wrapped,examined);}
    public void removeCity(UUID cityId){if(readOnly)return;boolean changed=false;for(EdgeKey key:List.copyOf(edgeCityIndex.getOrDefault(cityId,new LinkedHashSet<>()))){State state=states.get(key);unindexEdge(key);states.remove(key);infiltrationPlans.remove(key);if(state!=null&&state.invasionId()!=null)invasionCommitments.remove(state.invasionId());changed=true;}for(CellKey key:List.copyOf(cellCityIndex.getOrDefault(cityId,new LinkedHashSet<>()))){securityCells.remove(key);unindexCell(key);changed=true;}for(Iterator<CellKey>it=patrolCoverage.keySet().iterator();it.hasNext();)if(it.next().cityId().equals(cityId)){it.remove();changed=true;}for(UUID id:List.copyOf(assignmentCityIndex.getOrDefault(cityId,new LinkedHashSet<>()))){PatrolAssignment assignment=patrolAssignments.remove(id);if(assignment!=null){unindexAssignment(assignment);changed=true;}}assignmentCityIndex.remove(cityId);for(UUID id:List.copyOf(patrolCityIndex.getOrDefault(cityId,new LinkedHashSet<>()))){PatrolRoute route=patrolRoutes.remove(id);if(route!=null){removeIndex(patrolPostIndex,route.guardPostId(),id);changed=true;}}patrolCityIndex.remove(cityId);if(changed)setDirty();}
    public boolean readOnly(){return readOnly;}public int quarantinedEdges(){return quarantinedEdges;}public int quarantinedSecurityCells(){return quarantinedSecurityCells;}public int quarantinedPatrolRoutes(){return quarantinedPatrolRoutes;}public int quarantinedPatrolAssignments(){return quarantinedPatrolAssignments;}public int quarantinedPatrolCoverage(){return quarantinedPatrolCoverage;}public int quarantinedInfiltrationPlans(){return quarantinedInfiltrationPlans;}public int quarantinedInvasionCommitments(){return quarantinedInvasionCommitments;}public int patrolRouteCount(){return patrolRoutes.size();}public int patrolAssignmentCount(){return patrolAssignments.size();}public int patrolCoverageCount(){return patrolCoverage.size();}public int infiltrationPlanCount(){return infiltrationPlans.size();}public int invasionCommitmentCount(){return invasionCommitments.size();}public String migrationResult(){return migrationResult;}

    CompoundTag saveTag(){if(readOnly&&protectedRoot!=null)return protectedRoot.copy();CompoundTag root=new CompoundTag();root.putInt("SchemaVersion",SCHEMA_VERSION);root.putString("MigrationResult",migrationResult);root.putInt("QuarantinedEdges",quarantinedEdges);root.putInt("QuarantinedSecurityCells",quarantinedSecurityCells);root.putInt("QuarantinedPatrolRoutes",quarantinedPatrolRoutes);root.putInt("QuarantinedPatrolAssignments",quarantinedPatrolAssignments);root.putInt("QuarantinedPatrolCoverage",quarantinedPatrolCoverage);root.putInt("QuarantinedInfiltrationPlans",quarantinedInfiltrationPlans);root.putInt("QuarantinedInvasionCommitments",quarantinedInvasionCommitments);ListTag edges=new ListTag();states.forEach((key,state)->edges.add(saveEdge(key,state)));root.put("Edges",edges);ListTag cells=new ListTag();for(SecurityCell cell:securityCells.values())cells.add(saveCell(cell));root.put("SecurityCells",cells);ListTag routes=new ListTag();for(PatrolRoute route:patrolRoutes.values())routes.add(savePatrolRoute(route));root.put("PatrolRoutes",routes);ListTag assignments=new ListTag();for(PatrolAssignment assignment:patrolAssignments.values())assignments.add(savePatrolAssignment(assignment));root.put("PatrolAssignments",assignments);ListTag coverage=new ListTag();patrolCoverage.forEach((key,value)->coverage.add(savePatrolCoverage(key,value)));root.put("PatrolCoverage",coverage);ListTag plans=new ListTag();infiltrationPlans.forEach((key,value)->plans.add(saveInfiltrationPlan(key,value)));root.put("InfiltrationPlans",plans);ListTag commitments=new ListTag();for(InvasionCommitment commitment:invasionCommitments.values())commitments.add(saveInvasionCommitment(commitment));root.put("InvasionCommitments",commitments);return root;}

    static ThreatSavedData load(CompoundTag root){ThreatSavedData data=new ThreatSavedData();int schema=root.getIntOr("SchemaVersion",0);if(schema>SCHEMA_VERSION){data.readOnly=true;data.protectedRoot=root.copy();data.migrationResult="future_schema_read_only";LOGGER.warn("Civitas threat data schema {} is newer than {}; preserving it read-only",schema,SCHEMA_VERSION);return data;}data.migrationResult=schema<9?"v"+schema+"_to_v9":root.getStringOr("MigrationResult","v9");data.quarantinedEdges=Math.max(0,root.getIntOr("QuarantinedEdges",0));data.quarantinedSecurityCells=Math.max(0,root.getIntOr("QuarantinedSecurityCells",0));data.quarantinedPatrolRoutes=Math.max(0,root.getIntOr("QuarantinedPatrolRoutes",0));data.quarantinedPatrolAssignments=Math.max(0,root.getIntOr("QuarantinedPatrolAssignments",0));data.quarantinedPatrolCoverage=Math.max(0,root.getIntOr("QuarantinedPatrolCoverage",0));data.quarantinedInfiltrationPlans=Math.max(0,root.getIntOr("QuarantinedInfiltrationPlans",0));data.quarantinedInvasionCommitments=Math.max(0,root.getIntOr("QuarantinedInvasionCommitments",0));for(Tag raw:root.getListOrEmpty("Edges")){try{if(!(raw instanceof CompoundTag t))throw new IllegalArgumentException("edge not compound");var entry=loadEdge(t,schema);if(data.states.containsKey(entry.getKey())||entry.getValue().invasionId()!=null&&data.invasionEdgeIndex.containsKey(entry.getValue().invasionId()))throw new IllegalArgumentException("duplicate edge or invasion id");data.states.put(entry.getKey(),entry.getValue());data.indexEdge(entry.getKey());}catch(RuntimeException ex){data.quarantinedEdges++;LOGGER.warn("Skipping malformed Civitas threat edge",ex);}}for(Tag raw:root.getListOrEmpty("SecurityCells")){try{if(!(raw instanceof CompoundTag t))throw new IllegalArgumentException("cell not compound");SecurityCell cell=loadCell(t,schema);CellKey key=new CellKey(cell.cityId(),cell.chunk());if(data.securityCells.putIfAbsent(key,cell)!=null)throw new IllegalArgumentException("duplicate SecurityCell");data.indexCell(key);}catch(RuntimeException ex){data.quarantinedSecurityCells++;LOGGER.warn("Skipping malformed Civitas SecurityCell",ex);}}if(schema>=5)for(Tag raw:root.getListOrEmpty("PatrolRoutes")){try{if(!(raw instanceof CompoundTag t))throw new IllegalArgumentException("route not compound");PatrolRoute route=loadPatrolRoute(t);if(data.patrolRoutes.putIfAbsent(route.id(),route)!=null)throw new IllegalArgumentException("duplicate patrol route");data.indexPatrol(route);}catch(RuntimeException ex){data.quarantinedPatrolRoutes++;LOGGER.warn("Skipping malformed Civitas patrol route",ex);}}if(schema>=6)for(Tag raw:root.getListOrEmpty("PatrolAssignments")){try{if(!(raw instanceof CompoundTag t))throw new IllegalArgumentException("assignment not compound");PatrolAssignment assignment=loadPatrolAssignment(t);if(!data.patrolRoutes.containsKey(assignment.routeId())||data.patrolAssignments.putIfAbsent(assignment.id(),assignment)!=null||data.assignmentCitizenIndex.containsKey(assignment.citizenId())||data.assignmentRouteShiftIndex.containsKey(new RouteShiftKey(assignment.routeId(),assignment.shift())))throw new IllegalArgumentException("orphan or duplicate patrol assignment");data.indexAssignment(assignment);}catch(RuntimeException ex){data.quarantinedPatrolAssignments++;LOGGER.warn("Skipping malformed Civitas patrol assignment",ex);}}if(schema>=7)for(Tag raw:root.getListOrEmpty("PatrolCoverage")){try{if(!(raw instanceof CompoundTag t))throw new IllegalArgumentException("coverage not compound");var entry=loadPatrolCoverage(t);if(!data.patrolAssignments.containsKey(entry.getValue().assignmentId())||data.patrolCoverage.putIfAbsent(entry.getKey(),entry.getValue())!=null)throw new IllegalArgumentException("orphan or duplicate patrol coverage");}catch(RuntimeException ex){data.quarantinedPatrolCoverage++;LOGGER.warn("Skipping malformed Civitas patrol coverage",ex);}}if(schema>=8)for(Tag raw:root.getListOrEmpty("InfiltrationPlans")){try{if(!(raw instanceof CompoundTag t))throw new IllegalArgumentException("plan not compound");var entry=loadInfiltrationPlan(t);State state=data.states.get(entry.getKey());if(state==null||state.phase()!=Phase.WARNING&&state.phase()!=Phase.WAVE||data.infiltrationPlans.putIfAbsent(entry.getKey(),entry.getValue())!=null)throw new IllegalArgumentException("orphan or duplicate infiltration plan");}catch(RuntimeException ex){data.quarantinedInfiltrationPlans++;LOGGER.warn("Skipping malformed Civitas infiltration plan",ex);}}if(schema>=9)for(Tag raw:root.getListOrEmpty("InvasionCommitments")){try{if(!(raw instanceof CompoundTag t))throw new IllegalArgumentException("commitment not compound");InvasionCommitment commitment=loadInvasionCommitment(t);EdgeKey key=data.invasionEdgeIndex.get(commitment.invasionId());State state=key==null?null:data.states.get(key);if(state==null||state.phase()!=Phase.WAVE||!key.cityId().equals(commitment.cityId())||state.wave()!=commitment.wave()||state.remainingMobs()!=commitment.survivingEnemyIds().size()||data.invasionCommitments.putIfAbsent(commitment.invasionId(),commitment)!=null)throw new IllegalArgumentException("orphan or inconsistent invasion commitment");}catch(RuntimeException ex){data.quarantinedInvasionCommitments++;LOGGER.warn("Skipping malformed Civitas invasion commitment",ex);}}return data;}

    private void indexEdge(EdgeKey key){edgeCityIndex.computeIfAbsent(key.cityId(),ignored->new LinkedHashSet<>()).add(key);edgeChunkIndex.computeIfAbsent(new CellKey(key.cityId(),key.chunk()),ignored->new LinkedHashSet<>()).add(key);State state=states.get(key);if(state!=null&&state.invasionId()!=null)invasionEdgeIndex.put(state.invasionId(),key);}
    private void unindexEdge(EdgeKey key){State state=states.get(key);if(state!=null&&state.invasionId()!=null)invasionEdgeIndex.remove(state.invasionId(),key);removeIndex(edgeCityIndex,key.cityId(),key);removeIndex(edgeChunkIndex,new CellKey(key.cityId(),key.chunk()),key);}
    private void indexCell(CellKey key){cellCityIndex.computeIfAbsent(key.cityId(),ignored->new LinkedHashSet<>()).add(key);}
    private void indexPatrol(PatrolRoute route){patrolCityIndex.computeIfAbsent(route.cityId(),ignored->new LinkedHashSet<>()).add(route.id());patrolPostIndex.computeIfAbsent(route.guardPostId(),ignored->new LinkedHashSet<>()).add(route.id());}
    private void indexAssignment(PatrolAssignment assignment){assignmentCityIndex.computeIfAbsent(assignment.cityId(),ignored->new LinkedHashSet<>()).add(assignment.id());assignmentCitizenIndex.put(assignment.citizenId(),assignment.id());assignmentRouteShiftIndex.put(new RouteShiftKey(assignment.routeId(),assignment.shift()),assignment.id());assignmentRouteIndex.computeIfAbsent(assignment.routeId(),ignored->new LinkedHashSet<>()).add(assignment.id());}
    private void unindexAssignment(PatrolAssignment assignment){removeIndex(assignmentCityIndex,assignment.cityId(),assignment.id());assignmentCitizenIndex.remove(assignment.citizenId(),assignment.id());assignmentRouteShiftIndex.remove(new RouteShiftKey(assignment.routeId(),assignment.shift()),assignment.id());removeIndex(assignmentRouteIndex,assignment.routeId(),assignment.id());}
    private void markAssignmentsForRouteStale(UUID routeId,String reason){for(UUID id:List.copyOf(assignmentRouteIndex.getOrDefault(routeId,new LinkedHashSet<>()))){PatrolAssignment assignment=patrolAssignments.get(id);if(assignment!=null)patrolAssignments.put(id,assignment.withState(PatrolAssignment.Status.ROUTE_STALE,reason,assignment.nodeIndex(),assignment.forward(),assignment.lastProgressAt(),assignment.lastCoverageAt()));}}
    private static boolean sameIdentity(PatrolAssignment a,PatrolAssignment b){return a.id().equals(b.id())&&a.cityId().equals(b.cityId())&&a.routeId().equals(b.routeId())&&a.guardPostId().equals(b.guardPostId())&&a.citizenId().equals(b.citizenId())&&a.shift()==b.shift();}
    private void unindexCell(CellKey key){removeIndex(cellCityIndex,key.cityId(),key);}
    private static<K,V>void removeIndex(Map<K,LinkedHashSet<V>>index,K owner,V value){LinkedHashSet<V>keys=index.get(owner);if(keys!=null){keys.remove(value);if(keys.isEmpty())index.remove(owner);}}

    private static CompoundTag saveEdge(EdgeKey key,State state){CompoundTag t=new CompoundTag();t.putString("CityId",key.cityId.toString());t.putLong("Chunk",key.chunk);t.putString("Direction",key.direction.name());t.putDouble("Pressure",state.pressure);t.putString("Phase",state.phase.name());t.putLong("PhaseStartedAt",state.phaseStartedAt);t.putLong("CooldownUntil",state.cooldownUntil);t.putInt("Wave",state.wave);if(state.invasionId!=null)t.putString("InvasionId",state.invasionId.toString());t.putInt("RemainingMobs",state.remainingMobs);t.putInt("FailedDefenses",state.failedDefenses);t.putLong("LastUpdatedAt",state.lastUpdatedAt);return t;}
    private static Map.Entry<EdgeKey,State>loadEdge(CompoundTag t,int schema){UUID city=UUID.fromString(t.getStringOr("CityId",""));long chunk=t.getLongOr("Chunk",0);var direction=TerritoryTopology.Direction.valueOf(t.getStringOr("Direction","NORTH"));Phase phase=enumValue(Phase.class,t.getStringOr("Phase","CALM"),Phase.CALM);String invasion=t.getStringOr("InvasionId","");int remaining=schema>=4?t.getIntOr("RemainingMobs",0):phase==Phase.WAVE?256:0;return Map.entry(new EdgeKey(city,chunk,direction),new State(t.getDoubleOr("Pressure",0),phase,t.getLongOr("PhaseStartedAt",0),t.getLongOr("CooldownUntil",0),t.getIntOr("Wave",0),invasion.isEmpty()?null:UUID.fromString(invasion),remaining,t.getIntOr("FailedDefenses",0),t.getLongOr("LastUpdatedAt",0)));}

    private static CompoundTag saveCell(SecurityCell c){CompoundTag t=new CompoundTag();t.putString("CityId",c.cityId().toString());t.putLong("Chunk",c.chunk());SecurityCellEvidence e=c.evidence();t.putDouble("Civility",e.civility());t.putDouble("Activity",e.activity());t.putDouble("BuiltSafety",e.builtSafety());t.putDouble("PatrolCoverage",e.patrolCoverage());t.putDouble("GuardResponse",e.guardResponse());t.putBoolean("PatrolEvidenceLinked",e.patrolEvidenceLinked());t.putBoolean("GuardEvidenceLinked",e.guardEvidenceLinked());t.putDouble("InfiltrationAccess",e.infiltrationAccess());t.putDouble("UndergroundDarkness",e.undergroundDarkness());t.putBoolean("InfiltrationEvidenceLinked",e.infiltrationEvidenceLinked());t.putBoolean("UndergroundEvidenceLinked",e.undergroundEvidenceLinked());t.putInt("BorderDistance",e.borderDistance());t.putBoolean("BorderTopologyLimited",e.borderTopologyLimited());t.putString("Neglect",e.neglectStage().name());t.putString("LastDefense",e.lastDefenseResult().name());t.putLong("LastDefenseAt",e.lastDefenseAt());t.putInt("TerritorySize",e.territorySize());t.putInt("ValidBuildings",e.validBuildings());t.putInt("ValidatedEntrances",e.validatedEntrances());t.putBoolean("BuildingEvidenceLinked",e.buildingEvidenceLinked());t.putLong("AssessedAt",e.assessedAt());ListTag contributions=new ListTag();c.contributions().forEach((factor,value)->{CompoundTag p=new CompoundTag();p.putString("Factor",factor.name());p.putDouble("Risk",value.risk());p.putDouble("Weight",value.weight());p.putDouble("Weighted",value.weightedRisk());contributions.add(p);});t.put("Contributions",contributions);t.putDouble("DiagnosticRisk",c.diagnosticRisk());t.putString("PrimaryFactor",c.primaryFactor().name());t.putIntArray("Missing",c.missingEvidence().stream().mapToInt(Enum::ordinal).toArray());t.putLong("Revision",c.revision());return t;}
    private static SecurityCell loadCell(CompoundTag t,int schema){UUID city=UUID.fromString(t.getStringOr("CityId",""));SecurityCellEvidence e=new SecurityCellEvidence(t.getDoubleOr("Civility",0),t.getDoubleOr("Activity",0),t.getDoubleOr("BuiltSafety",0),t.getIntOr("BorderDistance",0),t.getBooleanOr("BorderTopologyLimited",false),NeglectStage.valueOf(t.getStringOr("Neglect","HEALTHY")),TerritoryChunkState.DefenseResult.valueOf(t.getStringOr("LastDefense","NONE")),t.getLongOr("LastDefenseAt",0),t.getIntOr("TerritorySize",1),t.getIntOr("ValidBuildings",0),t.getIntOr("ValidatedEntrances",0),schema>=3&&t.getBooleanOr("BuildingEvidenceLinked",false),schema>=7?t.getDoubleOr("PatrolCoverage",0):0,schema>=7?t.getDoubleOr("GuardResponse",0):0,schema>=7&&t.getBooleanOr("PatrolEvidenceLinked",false),schema>=7&&t.getBooleanOr("GuardEvidenceLinked",false),schema>=8?t.getDoubleOr("InfiltrationAccess",0):0,schema>=8?t.getDoubleOr("UndergroundDarkness",0):0,schema>=8&&t.getBooleanOr("InfiltrationEvidenceLinked",false),schema>=8&&t.getBooleanOr("UndergroundEvidenceLinked",false),t.getLongOr("AssessedAt",0));EnumMap<SecurityFactor,SecurityContribution>parts=new EnumMap<>(SecurityFactor.class);for(Tag raw:t.getListOrEmpty("Contributions")){if(!(raw instanceof CompoundTag p))throw new IllegalArgumentException("contribution not compound");SecurityFactor factor=SecurityFactor.valueOf(p.getStringOr("Factor",""));if(parts.putIfAbsent(factor,new SecurityContribution(p.getDoubleOr("Risk",0),p.getDoubleOr("Weight",0),p.getDoubleOr("Weighted",0)))!=null)throw new IllegalArgumentException("duplicate contribution");}EnumSet<SecurityCell.MissingEvidence>missing=EnumSet.noneOf(SecurityCell.MissingEvidence.class);for(int ordinal:t.getIntArray("Missing").orElseGet(()->new int[0])){if(ordinal<0||ordinal>=SecurityCell.MissingEvidence.values().length)throw new IllegalArgumentException("invalid missing evidence");missing.add(SecurityCell.MissingEvidence.values()[ordinal]);}if(schema<3)missing.add(SecurityCell.MissingEvidence.BUILDING_RECORD_LINK);if(schema<7){missing.add(SecurityCell.MissingEvidence.PATROL_COVERAGE);missing.add(SecurityCell.MissingEvidence.GUARD_RESPONSE);}if(schema<8){missing.add(SecurityCell.MissingEvidence.INFILTRATION_SOURCE);missing.add(SecurityCell.MissingEvidence.UNDERGROUND_DARKNESS);}return new SecurityCell(city,t.getLongOr("Chunk",0),e,parts,t.getDoubleOr("DiagnosticRisk",0),SecurityFactor.valueOf(t.getStringOr("PrimaryFactor","CIVILITY")),missing,t.getLongOr("Revision",0));}
    private static CompoundTag savePatrolRoute(PatrolRoute route){CompoundTag t=new CompoundTag();t.putString("Id",route.id().toString());t.putString("CityId",route.cityId().toString());t.putString("Dimension",route.dimension());t.putString("GuardPostId",route.guardPostId().toString());t.putLongArray("Nodes",route.nodes().stream().mapToLong(Long::longValue).toArray());t.putString("CreatedBy",route.createdBy().toString());t.putString("Status",route.status().name());t.putLong("ValidatedAt",route.validatedAt());t.putLong("Revision",route.revision());t.putString("InvalidReason",route.invalidReason());return t;}
    private static PatrolRoute loadPatrolRoute(CompoundTag t){long[]raw=t.getLongArray("Nodes").orElseThrow(()->new IllegalArgumentException("missing patrol nodes"));List<Long>nodes=java.util.Arrays.stream(raw).boxed().toList();return new PatrolRoute(UUID.fromString(t.getStringOr("Id","")),UUID.fromString(t.getStringOr("CityId","")),t.getStringOr("Dimension",""),UUID.fromString(t.getStringOr("GuardPostId","")),nodes,UUID.fromString(t.getStringOr("CreatedBy","")),PatrolRoute.Status.valueOf(t.getStringOr("Status","")),t.getLongOr("ValidatedAt",0),t.getLongOr("Revision",0),t.getStringOr("InvalidReason",""));}
    private static CompoundTag savePatrolAssignment(PatrolAssignment a){CompoundTag t=new CompoundTag();t.putString("Id",a.id().toString());t.putString("CityId",a.cityId().toString());t.putString("RouteId",a.routeId().toString());t.putString("GuardPostId",a.guardPostId().toString());t.putString("CitizenId",a.citizenId().toString());t.putString("Shift",a.shift().name());t.putBoolean("Forced",a.forced());t.putDouble("Willingness",a.willingness().score());CompoundTag parts=new CompoundTag();a.willingness().components().forEach(parts::putDouble);t.put("WillingnessComponents",parts);t.putString("Status",a.status().name());t.putInt("NodeIndex",a.nodeIndex());t.putBoolean("Forward",a.forward());t.putLong("AssignedAt",a.assignedAt());t.putLong("LastProgressAt",a.lastProgressAt());t.putLong("LastCoverageAt",a.lastCoverageAt());t.putLong("Revision",a.revision());t.putString("InactiveReason",a.inactiveReason());return t;}
    private static PatrolAssignment loadPatrolAssignment(CompoundTag t){CompoundTag raw=t.getCompoundOrEmpty("WillingnessComponents");LinkedHashMap<String,Double>parts=new LinkedHashMap<>();for(String key:raw.keySet())parts.put(key,raw.getDoubleOr(key,0));GuardWillingness willingness=new GuardWillingness(t.getDoubleOr("Willingness",0),parts);return new PatrolAssignment(UUID.fromString(t.getStringOr("Id","")),UUID.fromString(t.getStringOr("CityId","")),UUID.fromString(t.getStringOr("RouteId","")),UUID.fromString(t.getStringOr("GuardPostId","")),UUID.fromString(t.getStringOr("CitizenId","")),GuardShift.valueOf(t.getStringOr("Shift","")),t.getBooleanOr("Forced",false),willingness,PatrolAssignment.Status.valueOf(t.getStringOr("Status","")),t.getIntOr("NodeIndex",0),t.getBooleanOr("Forward",true),t.getLongOr("AssignedAt",0),t.getLongOr("LastProgressAt",0),t.getLongOr("LastCoverageAt",0),t.getLongOr("Revision",0),t.getStringOr("InactiveReason",""));}
    private static CompoundTag savePatrolCoverage(CellKey key,PatrolCoverage coverage){CompoundTag t=new CompoundTag();t.putString("CityId",key.cityId().toString());t.putLong("Chunk",key.chunk());t.putLong("LastPatrolledAt",coverage.lastPatrolledAt());t.putLong("LastVisibleGuardAt",coverage.lastVisibleGuardAt());t.putString("AssignmentId",coverage.assignmentId().toString());return t;}
    private static Map.Entry<CellKey,PatrolCoverage>loadPatrolCoverage(CompoundTag t){CellKey key=new CellKey(UUID.fromString(t.getStringOr("CityId","")),t.getLongOr("Chunk",0));PatrolCoverage coverage=new PatrolCoverage(t.getLongOr("LastPatrolledAt",0),t.getLongOr("LastVisibleGuardAt",0),UUID.fromString(t.getStringOr("AssignmentId","")));return Map.entry(key,coverage);}
    private static CompoundTag saveInfiltrationPlan(EdgeKey key,InfiltrationPlan plan){CompoundTag t=new CompoundTag();t.putString("CityId",key.cityId().toString());t.putLong("EdgeChunk",key.chunk());t.putString("Direction",key.direction().name());t.putLong("CityRevision",plan.cityRevision());t.putInt("SelectedIndex",plan.selectedIndex());t.putLong("AssessedAt",plan.assessedAt());t.putInt("ExaminedCells",plan.examinedCells());t.putInt("WorldSamples",plan.worldSamples());t.putBoolean("Truncated",plan.truncated());ListTag candidates=new ListTag();for(InfiltrationCandidate candidate:plan.candidates()){CompoundTag c=new CompoundTag();c.putString("Source",candidate.source().name());c.putLong("Position",candidate.position());c.putLong("Chunk",candidate.chunk());c.putDouble("SourceWeight",candidate.sourceWeight());c.putDouble("SecurityRisk",candidate.securityRisk());c.putDouble("Darkness",candidate.darkness());c.putDouble("Unguarded",candidate.unguarded());c.putDouble("FinalWeight",candidate.finalWeight());candidates.add(c);}t.put("Candidates",candidates);return t;}
    private static Map.Entry<EdgeKey,InfiltrationPlan>loadInfiltrationPlan(CompoundTag t){UUID city=UUID.fromString(t.getStringOr("CityId",""));EdgeKey key=new EdgeKey(city,t.getLongOr("EdgeChunk",0),TerritoryTopology.Direction.valueOf(t.getStringOr("Direction","")));ArrayList<InfiltrationCandidate>candidates=new ArrayList<>();for(Tag raw:t.getListOrEmpty("Candidates")){if(!(raw instanceof CompoundTag c))throw new IllegalArgumentException("candidate not compound");candidates.add(new InfiltrationCandidate(InfiltrationSource.valueOf(c.getStringOr("Source","")),c.getLongOr("Position",0),c.getLongOr("Chunk",0),c.getDoubleOr("SourceWeight",0),c.getDoubleOr("SecurityRisk",0),c.getDoubleOr("Darkness",0),c.getDoubleOr("Unguarded",0),c.getDoubleOr("FinalWeight",0)));}InfiltrationPlan plan=new InfiltrationPlan(city,t.getLongOr("CityRevision",0),candidates,t.getIntOr("SelectedIndex",-1),t.getLongOr("AssessedAt",0),t.getIntOr("ExaminedCells",0),t.getIntOr("WorldSamples",0),t.getBooleanOr("Truncated",false));return Map.entry(key,plan);}
    private static CompoundTag saveInvasionCommitment(InvasionCommitment commitment){CompoundTag t=new CompoundTag();t.putString("InvasionId",commitment.invasionId().toString());t.putString("CityId",commitment.cityId().toString());t.putString("Source",commitment.source().name());t.putLong("Location",commitment.location());t.putInt("Wave",commitment.wave());ListTag enemies=new ListTag();for(UUID id:commitment.survivingEnemyIds()){CompoundTag e=new CompoundTag();e.putString("Id",id.toString());enemies.add(e);}t.put("SurvivingEnemies",enemies);ListTag participants=new ListTag();for(var participant:commitment.participants()){CompoundTag p=new CompoundTag();p.putString("CitizenId",participant.citizenId().toString());p.putString("Role",participant.role().name());p.putInt("Distance",participant.distanceBlocks());participants.add(p);}t.put("Participants",participants);t.putLong("CommittedAt",commitment.committedAt());t.putLong("LastRoundAt",commitment.lastRoundAt());t.putInt("Round",commitment.round());t.putLong("Revision",commitment.revision());return t;}
    private static InvasionCommitment loadInvasionCommitment(CompoundTag t){ArrayList<UUID>enemies=new ArrayList<>();for(Tag raw:t.getListOrEmpty("SurvivingEnemies")){if(!(raw instanceof CompoundTag e))throw new IllegalArgumentException("enemy not compound");enemies.add(UUID.fromString(e.getStringOr("Id","")));}ArrayList<InvasionCommitment.Participant>participants=new ArrayList<>();for(Tag raw:t.getListOrEmpty("Participants")){if(!(raw instanceof CompoundTag p))throw new IllegalArgumentException("participant not compound");participants.add(new InvasionCommitment.Participant(UUID.fromString(p.getStringOr("CitizenId","")),InvasionCommitment.Role.valueOf(p.getStringOr("Role","")),p.getIntOr("Distance",0)));}return new InvasionCommitment(UUID.fromString(t.getStringOr("InvasionId","")),UUID.fromString(t.getStringOr("CityId","")),InfiltrationSource.valueOf(t.getStringOr("Source","")),t.getLongOr("Location",0),t.getIntOr("Wave",0),enemies,participants,t.getLongOr("CommittedAt",0),t.getLongOr("LastRoundAt",0),t.getIntOr("Round",0),t.getLongOr("Revision",0));}
    private static double decay(long age,long memory){if(memory<1||age>=memory)return 0;if(age<=0)return 100;return 100.0*(1.0-age/(double)memory);}
    private static<E extends Enum<E>>E enumValue(Class<E>type,String value,E fallback){try{return Enum.valueOf(type,value);}catch(IllegalArgumentException ex){return fallback;}}
}
